package runtime

import (
	"context"
	"testing"
	"time"

	"socialpredict/models/modelstesting"

	"gorm.io/gorm"
)

func TestInitDBReturnsExplicitHandleWithoutSharedFallback(t *testing.T) {
	original := GetDB()
	t.Cleanup(func() {
		SetDB(original)
	})

	want := modelstesting.NewFakeDB(t)
	legacy := modelstesting.NewFakeDB(t)
	SetDB(legacy)
	factory := stubFactory{db: want}

	got, err := InitDB(DBConfig{
		Host:            "localhost",
		User:            "postgres",
		Name:            "socialpredict",
		MaxOpenConns:    12,
		MaxIdleConns:    4,
		ConnMaxLifetime: time.Hour,
		ConnMaxIdleTime: 10 * time.Minute,
	}, factory)
	if err != nil {
		t.Fatalf("InitDB returned error: %v", err)
	}

	if got != want {
		t.Fatalf("expected InitDB to return factory db")
	}
	if shared := GetDB(); shared != legacy {
		t.Fatalf("expected InitDB not to replace shared db handle")
	}

	sqlDB, err := got.DB()
	if err != nil {
		t.Fatalf("db.DB: %v", err)
	}
	stats := sqlDB.Stats()
	if stats.MaxOpenConnections != 12 {
		t.Fatalf("expected max open connections to be configured, got %d", stats.MaxOpenConnections)
	}
}

func TestBuildPostgresDSNDefaultsAndValidation(t *testing.T) {
	dsn, err := BuildPostgresDSN(DBConfig{
		Host:     " localhost ",
		User:     " postgres ",
		Password: "secret",
		Name:     " socialpredict ",
	})
	if err != nil {
		t.Fatalf("BuildPostgresDSN returned error: %v", err)
	}

	want := "host=localhost user=postgres password=secret dbname=socialpredict port=5432 sslmode=disable TimeZone=UTC"
	if dsn != want {
		t.Fatalf("unexpected dsn: %q", dsn)
	}

	if _, err := BuildPostgresDSN(DBConfig{}); err == nil {
		t.Fatalf("expected validation error for empty config")
	}
}

func TestBuildPostgresDSNRequiresTLSWhenConfigured(t *testing.T) {
	cfg := DBConfig{
		Host:       "localhost",
		User:       "postgres",
		Name:       "socialpredict",
		SSLMode:    "disable",
		RequireTLS: true,
	}
	if _, err := BuildPostgresDSN(cfg); err == nil {
		t.Fatalf("expected TLS posture validation error")
	}

	cfg.SSLMode = "verify-full"
	if _, err := BuildPostgresDSN(cfg); err != nil {
		t.Fatalf("expected verify-full to satisfy required TLS posture: %v", err)
	}
}

func TestLoadDBConfigFromEnv(t *testing.T) {
	t.Setenv("DB_HOST", "dbhost")
	t.Setenv("POSTGRES_USER", "pguser")
	t.Setenv("POSTGRES_PASSWORD", "pgpass")
	t.Setenv("POSTGRES_DATABASE", "pgdb")
	t.Setenv("POSTGRES_PORT", "6543")
	t.Setenv("DB_SSLMODE", "verify-full")
	t.Setenv("DB_REQUIRE_TLS", "true")
	t.Setenv("DB_MAX_OPEN_CONNS", "11")
	t.Setenv("DB_MAX_IDLE_CONNS", "3")
	t.Setenv("DB_CONN_MAX_LIFETIME", "45m")
	t.Setenv("DB_CONN_MAX_IDLE_TIME", "90s")

	cfg, err := LoadDBConfigFromEnv()
	if err != nil {
		t.Fatalf("LoadDBConfigFromEnv returned error: %v", err)
	}

	if cfg.Host != "dbhost" || cfg.User != "pguser" || cfg.Password != "pgpass" || cfg.Name != "pgdb" || cfg.Port != "6543" {
		t.Fatalf("unexpected config: %+v", cfg)
	}
	if cfg.SSLMode != "verify-full" || cfg.TimeZone != "UTC" || !cfg.RequireTLS {
		t.Fatalf("unexpected ssl/timezone config: %+v", cfg)
	}
	if cfg.MaxOpenConns != 11 || cfg.MaxIdleConns != 3 || cfg.ConnMaxLifetime != 45*time.Minute || cfg.ConnMaxIdleTime != 90*time.Second {
		t.Fatalf("unexpected pool config: %+v", cfg)
	}
}

func TestLoadDBConfigFromEnvProductionRequiresTLSByDefault(t *testing.T) {
	t.Setenv("APP_ENV", "production")
	t.Setenv("DB_HOST", "dbhost")
	t.Setenv("POSTGRES_USER", "pguser")
	t.Setenv("POSTGRES_DATABASE", "pgdb")

	cfg, err := LoadDBConfigFromEnv()
	if err != nil {
		t.Fatalf("LoadDBConfigFromEnv returned error: %v", err)
	}
	if !cfg.RequireTLS {
		t.Fatalf("expected production runtime to require TLS by default")
	}
	if _, err := BuildPostgresDSN(cfg); err == nil {
		t.Fatalf("expected default disabled sslmode to fail production TLS posture")
	}
}

func TestCheckDBReadiness(t *testing.T) {
	t.Run("ready", func(t *testing.T) {
		db := modelstesting.NewFakeDB(t)

		if err := CheckDBReadiness(context.Background(), db); err != nil {
			t.Fatalf("CheckDBReadiness returned error: %v", err)
		}
	})

	t.Run("nil db", func(t *testing.T) {
		if err := CheckDBReadiness(context.Background(), nil); err == nil {
			t.Fatal("expected error for nil db")
		}
	})

	t.Run("closed db", func(t *testing.T) {
		db := modelstesting.NewFakeDB(t)
		sqlDB, err := db.DB()
		if err != nil {
			t.Fatalf("db.DB: %v", err)
		}
		if err := sqlDB.Close(); err != nil {
			t.Fatalf("close sql db: %v", err)
		}

		if err := CheckDBReadiness(context.Background(), db); err == nil {
			t.Fatal("expected readiness check to fail for closed db")
		}
	})
}

func TestCloseDB(t *testing.T) {
	db := modelstesting.NewFakeDB(t)
	if err := CloseDB(db); err != nil {
		t.Fatalf("CloseDB returned error: %v", err)
	}
	if err := CheckDBReadiness(context.Background(), db); err == nil {
		t.Fatalf("expected closed db to fail readiness")
	}
}

type stubFactory struct {
	db  *gorm.DB
	err error
}

func (s stubFactory) Open(DBConfig) (*gorm.DB, error) {
	return s.db, s.err
}

package runtime

import (
	"os"
	"testing"
)

func TestLoadStartupMutationModeDefaultsToNonWriter(t *testing.T) {
	unsetEnvForTest(t, StartupWriterEnv)
	unsetEnvForTest(t, legacyStartupWriterEnv)

	mode, err := LoadStartupMutationModeFromEnv()
	if err != nil {
		t.Fatalf("LoadStartupMutationModeFromEnv returned error: %v", err)
	}
	if mode.Writer {
		t.Fatalf("expected default startup mutation mode to be non-writer")
	}
	if mode.Source != "default" {
		t.Fatalf("expected default startup mutation source, got %q", mode.Source)
	}
}

func TestLoadStartupMutationModePrimaryFlagTakesPrecedence(t *testing.T) {
	t.Setenv(StartupWriterEnv, "0")
	t.Setenv(legacyStartupWriterEnv, "true")

	mode, err := LoadStartupMutationModeFromEnv()
	if err != nil {
		t.Fatalf("LoadStartupMutationModeFromEnv returned error: %v", err)
	}
	if mode.Writer {
		t.Fatalf("expected explicit false startup writer flag to disable writer mode")
	}
	if mode.Source != StartupWriterEnv {
		t.Fatalf("expected primary startup writer env source, got %q", mode.Source)
	}
}

func TestLoadStartupMutationModeUsesLegacyWhenPrimaryMissing(t *testing.T) {
	t.Setenv(legacyStartupWriterEnv, "true")

	mode, err := LoadStartupMutationModeFromEnv()
	if err != nil {
		t.Fatalf("LoadStartupMutationModeFromEnv returned error: %v", err)
	}
	if !mode.Writer {
		t.Fatalf("expected legacy startup writer flag to enable writer mode")
	}
	if mode.Source != legacyStartupWriterEnv {
		t.Fatalf("expected legacy startup writer env source, got %q", mode.Source)
	}
}

func TestLoadStartupMutationModeRejectsInvalidFlag(t *testing.T) {
	t.Setenv(StartupWriterEnv, "sometimes")

	if _, err := LoadStartupMutationModeFromEnv(); err == nil {
		t.Fatalf("expected invalid startup writer flag to fail closed")
	}
}

func unsetEnvForTest(t *testing.T, key string) {
	t.Helper()

	original, existed := os.LookupEnv(key)
	if err := os.Unsetenv(key); err != nil {
		t.Fatalf("Unsetenv(%s): %v", key, err)
	}
	t.Cleanup(func() {
		if existed {
			if err := os.Setenv(key, original); err != nil {
				t.Fatalf("Setenv(%s): %v", key, err)
			}
			return
		}
		if err := os.Unsetenv(key); err != nil {
			t.Fatalf("Unsetenv(%s): %v", key, err)
		}
	})
}

package bets_test

import (
	"context"
	"errors"
	"testing"
	"time"

	bets "socialpredict/internal/domain/bets"
	"socialpredict/internal/domain/boundary"
	dmarkets "socialpredict/internal/domain/markets"
	dusers "socialpredict/internal/domain/users"
	"socialpredict/models/modelstesting"
)

var errUnexpectedServiceCall = errors.New("unexpected call")

type fakeRepo struct {
	created *boundary.Bet
	writer  fakeBetWriter
	history fakeBetHistoryReader
}

type fakePlaceUnit struct {
	repo  bets.Repository
	users bets.UserService
}

func (f fakePlaceUnit) PlaceBetTransaction(ctx context.Context, fn bets.PlaceTransactionFunc) error {
	return fn(ctx, f.repo, f.users)
}

func newFakeRepo(opts ...func(*fakeRepo)) *fakeRepo {
	repo := &fakeRepo{
		writer: fakeBetWriter{
			createFunc: func(context.Context, *boundary.Bet) error { return nil },
		},
		history: fakeBetHistoryReader{
			hasBetFunc: func(context.Context, uint, string) (bool, error) { return false, nil },
		},
	}
	for _, opt := range opts {
		opt(repo)
	}
	return repo
}

func withFakeRepoCreate(fn func(ctx context.Context, bet *boundary.Bet) error) func(*fakeRepo) {
	return func(repo *fakeRepo) {
		repo.writer.createFunc = fn
	}
}

func withFakeRepoHasBet(fn func(ctx context.Context, marketID uint, username string) (bool, error)) func(*fakeRepo) {
	return func(repo *fakeRepo) {
		repo.history.hasBetFunc = fn
	}
}

type fakeBetWriter struct {
	createFunc func(ctx context.Context, bet *boundary.Bet) error
}

func (f *fakeRepo) Create(ctx context.Context, bet *boundary.Bet) error {
	return f.writer.Create(ctx, bet, f)
}

type fakeBetHistoryReader struct {
	hasBetFunc func(ctx context.Context, marketID uint, username string) (bool, error)
}

func (f *fakeRepo) UserHasBet(ctx context.Context, marketID uint, username string) (bool, error) {
	return f.history.UserHasBet(ctx, marketID, username)
}

func (f fakeBetWriter) Create(ctx context.Context, bet *boundary.Bet, repo *fakeRepo) error {
	if f.createFunc == nil {
		return errUnexpectedServiceCall
	}
	if err := f.createFunc(ctx, bet); err != nil {
		return err
	}
	if bet == nil {
		repo.created = nil
		return nil
	}
	copied := *bet
	repo.created = &copied
	return nil
}

func (f fakeBetHistoryReader) UserHasBet(ctx context.Context, marketID uint, username string) (bool, error) {
	if f.hasBetFunc == nil {
		return false, errUnexpectedServiceCall
	}
	return f.hasBetFunc(ctx, marketID, username)
}

