func TestSaleCalculator_Calculate(t *testing.T) {
	calc := saleCalculator{maxDustPerSale: 3}
	pos := &dmarkets.UserPosition{Value: 100}
	tests := []struct {
		name           string
		position       *dmarkets.UserPosition
		sharesOwned    int64
		requested      int64
		want           SaleQuote
		wantErr        error
		wantDustCapErr bool
	}{
		{
			name:        "successful sale",
			position:    pos,
			sharesOwned: 10,
			requested:   23,
			want:        SaleQuote{SharesToSell: 2, SaleValue: 20, Dust: 3},
		},
		{
			name:        "request too small",
			position:    pos,
			sharesOwned: 10,
			requested:   5,
			wantErr:     ErrInvalidAmount,
		},
		{
			name:           "dust cap exceeded",
			position:       pos,
			sharesOwned:    10,
			requested:      35,
			wantDustCapErr: true,
		},
	}

	for _, tc := range tests {
		t.Run(tc.name, func(t *testing.T) {
			result, err := calc.Calculate(tc.position, tc.sharesOwned, tc.requested)
			switch {
			case tc.wantDustCapErr:
				var dustErr ErrDustCapExceeded
				if !errors.As(err, &dustErr) {
					t.Fatalf("expected dust cap error, got %v", err)
				}
			case tc.wantErr != nil:
				if !errors.Is(err, tc.wantErr) {
					t.Fatalf("expected %v, got %v", tc.wantErr, err)
				}
			default:
				if err != nil {
					t.Fatalf("expected success, got %v", err)
				}
				if result != tc.want {
					t.Fatalf("unexpected sale result: %+v", result)
				}
			}
		})
	}

	if _, err := (saleCalculator{}).Calculate(nil, 0, 1); !errors.Is(err, ErrNoPosition) {
		t.Fatalf("expected zero-value calculator to keep base contract, got %v", err)
	}
}

	if fixture.repo.created == nil {
		t.Fatalf("expected repository Create to be called")
	}
	if fixture.repo.created.Outcome != "YES" {
		t.Fatalf("expected outcome YES, got %s", fixture.repo.created.Outcome)
	}

	if len(fixture.users.calls) != 1 {
		t.Fatalf("expected one ApplyTransaction call, got %d", len(fixture.users.calls))
	}
	totalCost := int64(100 + fixture.config.InitialBetFee + fixture.config.BuySharesFee)
	if fixture.users.calls[0].amount != totalCost {
		t.Fatalf("unexpected transaction amount: %d", fixture.users.calls[0].amount)
	}

	fallbackService := bets.NewService(fixture.repo, fixture.markets, fixture.users, bets.Config{}, nil, bets.WithClock(nil))
	if fallbackService == nil {
		t.Fatalf("expected fallback service")
	}
}

